import csv, ast, numpy as np
wind=[]
with open('/work/wind_profile_20260613_194946.csv') as f:
    for row in csv.DictReader(f):
        wind.append(ast.literal_eval(row['value'])['electricity']/1000.0)
w=np.array(wind); TARGET=30.0
eff=0.81**0.5; soc_lo,soc_hi=0.10,0.90

def simulate(P,duration=4.0):
    Enom=P*duration; cap_hi=soc_hi*Enom; cap_lo=soc_lo*Enom
    soc=cap_hi; dh=0
    for x in w:
        if x>=TARGET:
            chg=min(x-TARGET,P,(cap_hi-soc)/eff); soc+=chg*eff; out=TARGET
        else:
            dis=min(TARGET-x,P,(soc-cap_lo)*eff); soc-=dis/eff; out=x+dis
            if out<TARGET-1e-6: dh+=1
    return dh

for P in [150,200,250,300,350,400,500,600,800]:
    print(f"P={P} MW / {P*4} MWh (4-hr): deficit_hrs={simulate(P)}")

